<template>
	<view class="container">
		<view class="header">
			<text class="title">生产执行管理</text>
		</view>
		
		<view class="realtime-section">
			<view class="section-header">
				<text class="section-title">实时生产数据</text>
			</view>
			
			<view class="realtime-grid">
				<view class="realtime-card">
					<text class="card-label">当前产量</text>
					<text class="card-value">{{ currentProduction }}</text>
					<text class="card-unit">件</text>
				</view>
				
				<view class="realtime-card">
					<text class="card-label">生产效率</text>
					<text class="card-value">{{ productionEfficiency }}</text>
					<text class="card-unit">件/小时</text>
				</view>
				
				<view class="realtime-card">
					<text class="card-label">今日目标</text>
					<text class="card-value">{{ dailyTarget }}</text>
					<text class="card-unit">件</text>
				</view>
				
				<view class="realtime-card">
					<text class="card-label">完成率</text>
					<text class="card-value">{{ completionRate }}</text>
					<text class="card-unit">%</text>
				</view>
			</view>
		</view>
		
		<view class="workshop-section">
			<view class="section-header">
				<text class="section-title">车间状态</text>
			</view>
			
			<view class="workshop-list">
				<view class="workshop-item" v-for="(workshop, index) in workshops" :key="index">
					<view class="workshop-header">
						<text class="workshop-name">{{ workshop.name }}</text>
						<text class="workshop-status" :class="workshop.status">{{ workshop.statusText }}</text>
					</view>
					
					<view class="workshop-content">
						<view class="content-item">
							<text class="item-label">当前产品：</text>
							<text class="item-value">{{ workshop.currentProduct }}</text>
						</view>
						
						<view class="content-item">
							<text class="item-label">设备状态：</text>
							<view class="device-status">
								<view class="device-dot" :class="device.status" v-for="(device, idx) in workshop.devices" :key="idx"></view>
							</view>
						</view>
						
						<view class="content-item">
							<text class="item-label">生产进度：</text>
							<view class="progress-container">
								<view class="progress-bar" :style="{ width: workshop.progress + '%' }"></view>
							</view>
							<text class="progress-text">{{ workshop.progress }}%</text>
						</view>
					</view>
				</view>
			</view>
		</view>
		
		<view class="operation-section">
			<view class="section-header">
				<text class="section-title">生产操作</text>
			</view>
			
			<view class="operation-grid">
				<view class="operation-item" @click="recordProduction">
					<view class="operation-icon record"></view>
					<text class="operation-text">记录产量</text>
				</view>
				
				<view class="operation-item" @click="reportIssue">
					<view class="operation-icon issue"></view>
					<text class="operation-text">报告异常</text>
				</view>
				
				<view class="operation-item" @click="changeProduct">
					<view class="operation-icon change"></view>
					<text class="operation-text">切换产品</text>
				</view>
				
				<view class="operation-item" @click="viewHistory">
					<view class="operation-icon history"></view>
					<text class="operation-text">查看历史</text>
				</view>
			</view>
		</view>
	</view>
</template>

<script>
export default {
	data() {
		return {
			currentProduction: 128,
			productionEfficiency: 256,
			dailyTarget: 500,
			completionRate: 25.6,
			workshops: [
				{
					name: '车间1',
					status: 'running',
					statusText: '运行中',
					currentProduct: '产品A',
					devices: [
						{ status: 'running' },
						{ status: 'running' },
						{ status: 'running' },
						{ status: 'idle' }
					],
					progress: 65
				},
				{
					name: '车间2',
					status: 'idle',
					statusText: '空闲',
					currentProduct: '-',
					devices: [
						{ status: 'idle' },
						{ status: 'idle' },
						{ status: 'idle' },
						{ status: 'idle' }
					],
					progress: 0
				},
				{
					name: '车间3',
					status: 'maintenance',
					statusText: '维护中',
					currentProduct: '-',
					devices: [
						{ status: 'maintenance' },
						{ status: 'running' },
						{ status: 'maintenance' },
						{ status: 'idle' }
					],
					progress: 0
				}
			]
		};
	},
	methods: {
		recordProduction() {
			uni.showToast({
				title: '记录产量功能开发中',
				icon: 'none'
			});
		},
		reportIssue() {
			uni.showToast({
				title: '报告异常功能开发中',
				icon: 'none'
			});
		},
		changeProduct() {
			uni.showToast({
				title: '切换产品功能开发中',
				icon: 'none'
			});
		},
		viewHistory() {
			uni.showToast({
				title: '查看历史功能开发中',
				icon: 'none'
			});
		}
	}
};
</script>

<style scoped>
.container {
	padding: 20rpx;
	background-color: #f5f5f5;
	min-height: 100vh;
}

.header {
	padding: 20rpx;
	background-color: #fff;
	border-radius: 10rpx;
	margin-bottom: 20rpx;
	box-shadow: 0 2rpx 10rpx rgba(0, 0, 0, 0.1);
}

.title {
	font-size: 36rpx;
	font-weight: bold;
	color: #333;
}

.realtime-section {
	background-color: #fff;
	border-radius: 10rpx;
	padding: 20rpx;
	margin-bottom: 20rpx;
	box-shadow: 0 2rpx 10rpx rgba(0, 0, 0, 0.1);
}

.section-header {
	margin-bottom: 20rpx;
}

.section-title {
	font-size: 32rpx;
	font-weight: bold;
	color: #333;
}

.realtime-grid {
	display: grid;
	grid-template-columns: repeat(2, 1fr);
	gap: 20rpx;
}

.realtime-card {
	background-color: #f9f9f9;
	border-radius: 10rpx;
	padding: 20rpx;
	text-align: center;
	border-left: 5rpx solid #007aff;
}

.card-label {
	font-size: 24rpx;
	color: #666;
	margin-bottom: 10rpx;
}

.card-value {
	font-size: 48rpx;
	font-weight: bold;
	color: #007aff;
}

.card-unit {
	font-size: 24rpx;
	color: #8e8e93;
	margin-left: 8rpx;
}

.workshop-section {
	background-color: #fff;
	border-radius: 10rpx;
	padding: 20rpx;
	margin-bottom: 20rpx;
	box-shadow: 0 2rpx 10rpx rgba(0, 0, 0, 0.1);
}

.workshop-list {
	display: flex;
	flex-direction: column;
	gap: 15rpx;
}

.workshop-item {
	background-color: #f9f9f9;
	border-radius: 8rpx;
	padding: 15rpx;
}

.workshop-header {
	display: flex;
	justify-content: space-between;
	align-items: center;
	margin-bottom: 12rpx;
}

.workshop-name {
	font-size: 28rpx;
	font-weight: bold;
	color: #333;
}

.workshop-status {
	font-size: 24rpx;
	padding: 4rpx 12rpx;
	border-radius: 15rpx;
	font-weight: bold;
}

.workshop-status.running {
	background-color: #e8f8f5;
	color: #4cd964;
}

.workshop-status.idle {
	background-color: #f0f0f0;
	color: #8e8e93;
}

.workshop-status.maintenance {
	background-color: #fff3e0;
	color: #ff9500;
}

.workshop-content {
	display: flex;
	flex-direction: column;
	gap: 10rpx;
}

.content-item {
	display: flex;
	align-items: center;
}

.item-label {
	font-size: 24rpx;
	color: #666;
	width: 120rpx;
}

.item-value {
	font-size: 24rpx;
	color: #333;
}

.device-status {
	display: flex;
	gap: 8rpx;
}

.device-dot {
	width: 12rpx;
	height: 12rpx;
	border-radius: 50%;
}

.device-dot.running {
	background-color: #4cd964;
}

.device-dot.idle {
	background-color: #8e8e93;
}

.device-dot.maintenance {
	background-color: #ff9500;
}

.progress-container {
	flex: 1;
	height: 10rpx;
	background-color: #f0f0f0;
	border-radius: 5rpx;
	margin: 0 15rpx;
	overflow: hidden;
}

.progress-bar {
	height: 100%;
	background-color: #007aff;
	transition: width 0.3s ease;
}

.progress-text {
	font-size: 22rpx;
	color: #007aff;
	font-weight: bold;
}

.operation-section {
	background-color: #fff;
	border-radius: 10rpx;
	padding: 20rpx;
	box-shadow: 0 2rpx 10rpx rgba(0, 0, 0, 0.1);
}

.operation-grid {
	display: grid;
	grid-template-columns: repeat(2, 1fr);
	gap: 20rpx;
}

.operation-item {
	display: flex;
	flex-direction: column;
	align-items: center;
	padding: 25rpx;
	background-color: #f9f9f9;
	border-radius: 10rpx;
	cursor: pointer;
	transition: all 0.3s;
}

.operation-item:hover {
	background-color: #e8f0fe;
	transform: translateY(-2rpx);
}

.operation-icon {
	width: 80rpx;
	height: 80rpx;
	border-radius: 20rpx;
	margin-bottom: 15rpx;
}

.operation-icon.record {
	background-color: #007aff;
}

.operation-icon.issue {
	background-color: #ff2d55;
}

.operation-icon.change {
	background-color: #ff9500;
}

.operation-icon.history {
	background-color: #5856d6;
}

.operation-text {
	font-size: 24rpx;
	color: #333;
}
</style>